import asyncio
from typing import NoReturn
from .ollama_client import generate

def _print_welcome() -> None:
    print("\nWelcome to Local Ollama ChatGPT (type 'exit' or Ctrl‑D to quit)\n")

def _prompt_user() -> str:
    try:
        return input("You: ")
    except EOFError:
        return "exit"

def chat_loop() -> NoReturn:
    _print_welcome()
    while True:
        user_input = _prompt_user().strip()
        if user_input.lower() in {"exit", "quit"}:
            print("Goodbye! 👋")
            break
        if not user_input:
            continue
        try:
            response = asyncio.run(generate(user_input))
            print(f"ChatGPT: {response}\n")
        except Exception as exc:
            print(f"[Error] {exc}\n")

if __name__ == "__main__":
    chat_loop()

import asyncio
from typing import NoReturn
from .ollama_client import generate

def _print_welcome() -> None:
    print(
        "\nWelcome to Local Ollama ChatGPT (type 'exit' or Ctrl‑D to quit)"
        "\nEnter a multi‑line prompt and finish with a line containing only '---'\n"
    )

def _prompt_user() -> str:
    """Read either a single line or a multi‑line block terminated by '---'."""
    lines: list[str] = []
    while True:
        try:
            line = input()
        except EOFError:
            return "exit"
        if line.strip() == "---":
            break
        if not lines and line.lower() in {"exit", "quit"}:
            return "exit"
        lines.append(line)
    return "\n".join(lines).strip()

